# Triage result data model and scoring

from dataclasses import dataclass
from typing import Literal

TriageOutcome = Literal[
    'Agentic',
    'Human-in-Loop Agentic',
    'Assistive',
    'Constrained Agentic',
]

@dataclass
class TriageResult:
    use_case_id: str
    use_case_name: str
    outcome: TriageOutcome
    blocking_factor: str | None   # Why not fully agentic, if applicable
    recommended_autonomy_level: str
    review_trigger: str           # What should cause re-triage

def triage(answers: dict[str, bool], use_case_id: str, name: str) -> TriageResult:
    if not answers.get('Q1'):
        return TriageResult(
            use_case_id, name, 'Assistive',
            'Human decision authority cannot be delegated',
            'AI provides recommendations, human approves',
            'Re-triage when regulatory or policy framework changes',
        )
    if not answers.get('Q2'):
        return TriageResult(
            use_case_id, name, 'Human-in-Loop Agentic',
            'Error consequence is irreversible',
            'AI acts autonomously; human reviews within SLA before finalization',
            'Re-triage if error reversal process is improved',
        )
    if not answers.get('Q3'):
        return TriageResult(
            use_case_id, name, 'Constrained Agentic',
            'Ambiguous input requires confidence threshold gating',
            'AI acts on high-confidence inputs; escalates others',
            'Re-triage when model confidence calibration improves',
        )
    if not answers.get('Q4'):
        return TriageResult(
            use_case_id, name, 'Assistive',
            'Regulatory requirement mandates human decision-maker',
            'AI provides decision support; human signs off',
            'Re-triage when regulatory guidance is updated',
        )
    return TriageResult(
        use_case_id, name, 'Agentic',
        None,
        'AI acts autonomously end-to-end within defined scope',
        'Re-triage annually or on material process change',
    )
